	rubert: { maxLength: 512, useTokenTypeIds: true, useMeanPooling: false, doLowerCase: false, queryPrefix: "" },
	bge: { maxLength: 512, useTokenTypeIds: true, useMeanPooling: true, doLowerCase: true, queryPrefix: "Represent this sentence for searching relevant passages: " }
